content.content:
     1→"use client";
     2→
     3→import { useState, useEffect, useCallback, useRef } from "react";
     4→import { socket } from "@/lib/socket";
     5→import {
     6→  getUser,
     7→  updateProfile,
     8→  uploadSelfie,
     9→  startScrape,
    10→  submitOnboarding,
    11→  UserProfile,
    12→} from "@/lib/api";
    13→import type { OnboardingData } from "@/lib/types";
    14→import GoogleSignIn from "@/components/phone/GoogleSignIn";
    15→import SelfieCapture from "@/components/phone/SelfieCapture";
    16→import QueueStatus from "@/components/phone/QueueStatus";
    17→
    18→type PhoneState = "loading" | "signin" | "questionnaire" | "queue" | "idle" | "recap";
    19→
    20→const STORAGE_KEY = "mirrorless_user_id";
    21→
    22→export default function PhonePage() {
    23→  const [state, setState] = useState<PhoneState>("loading");
    24→  const [user, setUser] = useState<UserProfile | null>(null);
    25→  const [error, setError] = useState("");
    26→  const [recapData, setRecapData] = useState<{
    27→    summary?: string;
    28→    items_shown?: number;
    29→    items_liked?: number;
    30→  }>({});
    31→
    32→  // Shape of the actual session_ended payload from backend
    33→  interface SessionEndedPayload {
    34→    summary?: string;
    35→    stats?: { items_shown: number; likes: number; dislikes: number };
    36→    liked_items?: Array<{ title: string; price?: string; image_url?: string }>;
    37→    user_name?: string;
    38→  }
    39→
    40→  // Check for returning user on mount
    41→  useEffect(() => {
    42→    async function checkReturning() {
    43→      const savedId = localStorage.getItem(STORAGE_KEY);
    44→      if (savedId) {
    45→        try {
    46→          const existingUser = await getUser(savedId);
    47→          setUser(existingUser);
    48→          setState("queue");
    49→          return;
    50→        } catch {
    51→          localStorage.removeItem(STORAGE_KEY);
    52→        }
    53→      }
    54→      setState("signin");
    55→    }
    56→    checkReturning();
    57→  }, []);
    58→
    59→  // Connect socket when we have a user
    60→  useEffect(() => {
    61→    if (!user) return;
    62→    socket.connect();
    63→    socket.emit("join_room", { user_id: user.id });
    64→
    65→    const handleSessionEnded = (data: SessionEndedPayload) => {
    66→      setRecapData({
    67→        summary: data?.summary,
    68→        items_shown: data?.stats?.items_shown,
    69→        items_liked: data?.stats?.likes,
    70→      });
    71→      setState("recap");
    72→    };
    73→
    74→    socket.on("session_ended", handleSessionEnded);
    75→
    76→    return () => {
    77→      socket.off("session_ended", handleSessionEnded);
    78→    };
    79→  }, [user]);
    80→
    81→  const handleSignInComplete = useCallback(
    82→    (profile: UserProfile, selfieBase64: string | null, displayName: string) => {
    83→      setUser(profile);
    84→      localStorage.setItem(STORAGE_KEY, profile.id);
    85→
    86→      // Fire-and-forget: update name, upload selfie, start scrape
    87→      updateProfile(profile.id, displayName).catch(() => {});
    88→      if (selfieBase64) {
    89→        uploadSelfie(profile.id, selfieBase64).catch(() => {});
    90→      }
    91→      startScrape(profile.id).catch(() => {});
    92→
    93→      setState("questionnaire");
    94→    },
    95→    []
    96→  );
    97→
    98→  const handleQuestionnaireSubmit = useCallback(
    99→    async (data: OnboardingData) => {
   100→      if (!user) return;
   101→      await submitOnboarding(user.id, data);
   102→      setState("queue");
   103→    },
   104→    [user]
   105→  );
   106→
   107→  const handleBecameActive = useCallback(() => {
   108→    setState("idle");
   109→  }, []);
   110→
   111→  const handleLeaveQueue = useCallback(() => {
   112→    localStorage.removeItem(STORAGE_KEY);
   113→    setUser(null);
   114→    setState("signin");
   115→  }, []);
   116→
   117→  const handleDone = useCallback(() => {
   118→    localStorage.removeItem(STORAGE_KEY);
   119→    setUser(null);
   120→    setRecapData({});
   121→    setState("signin");
   122→  }, []);
   123→
   124→  if (state === "loading") {
   125→    return (
   126→      <main className="min-h-screen bg-white flex items-center justify-center">
   127→        <p className="text-zinc-400 animate-pulse">Loading...</p>
   128→      </main>
   129→    );
   130→  }
   131→
   132→  return (
   133→    <main className="min-h-screen bg-white text-zinc-900">
   134→      {state === "signin" && (
   135→        <SignInView onComplete={handleSignInComplete} error={error} setError={setError} />
   136→      )}
   137→      {state === "questionnaire" && (
   138→        <QuestionnaireView onSubmit={handleQuestionnaireSubmit} />
   139→      )}
   140→      {state === "queue" && user && (
   141→        <div className="flex flex-col items-center justify-center min-h-screen p-8">
   142→          <QueueStatus userId={user.id} onBecameActive={handleBecameActive} onLeave={handleLeaveQueue} />
   143→        </div>
   144→      )}
   145→      {state === "idle" && <IdleView />}
   146→      {state === "recap" && (
   147→        <RecapView data={recapData} onDone={handleDone} />
   148→      )}
   149→    </main>
   150→  );
   151→}
   152→
   153→/* ---------- SignIn View ---------- */
   154→
   155→function SignInView({
   156→  onComplete,
   157→  error,
   158→  setError,
   159→}: {
   160→  onComplete: (user: UserProfile, selfie: string | null, name: string) => void;
   161→  error: string;
   162→  setError: (e: string) => void;
   163→}) {
   164→  const [name, setName] = useState("");
   165→  const [selfie, setSelfie] = useState<string | null>(null);
   166→  const [oauthUser, setOauthUser] = useState<UserProfile | null>(null);
   167→
   168→  const handleGoogleSuccess = useCallback(
   169→    (user: UserProfile) => {
   170→      setOauthUser(user);
   171→      if (!name && user.name) setName(user.name);
   172→    },
   173→    [name]
   174→  );
   175→
   176→  const handleContinue = useCallback(() => {
   177→    if (!oauthUser) {
   178→      setError("Please sign in with Google first.");
   179→      return;
   180→    }
   181→    if (!name.trim()) {
   182→      setError("Please enter your name.");
   183→      return;
   184→    }
   185→    onComplete(oauthUser, selfie, name.trim());
   186→  }, [oauthUser, selfie, name, onComplete, setError]);
   187→
   188→  return (
   189→    <div className="flex flex-col items-center justify-center min-h-screen p-8 gap-8">
   190→      <div className="text-center">
   191→        <h1 className="text-3xl font-bold mb-2">Mirrorless</h1>
   192→        <p className="text-zinc-500">Your AI stylist awaits</p>
   193→      </div>
   194→
   195→      <SelfieCapture onCapture={setSelfie} />
   196→
   197→      <div className="w-full max-w-sm">
   198→        <label className="block text-sm font-semibold mb-1.5">Your name</label>
   199→        <input
   200→          value={name}
   201→          onChange={(e) => setName(e.target.value)}
   202→          placeholder="Enter your name"
   203→          className="w-full px-4 py-3 border border-zinc-200 rounded-xl text-base focus:outline-none focus:ring-2 focus:ring-zinc-900"
   204→        />
   205→      </div>
   206→
   207→      {!oauthUser ? (
   208→        <GoogleSignIn
   209→          onSuccess={handleGoogleSuccess}
   210→          onError={setError}
   211→        />
   212→      ) : (
   213→        <div className="flex items-center gap-2 text-sm text-green-600">
   214→          <span>✓</span>
   215→          <span>Signed in as {oauthUser.email}</span>
   216→        </div>
   217→      )}
   218→
   219→      {oauthUser && (
   220→        <button
   221→          onClick={handleContinue}
   222→          className="w-full max-w-sm bg-zinc-900 text-white rounded-xl py-4 text-base font-semibold"
   223→        >
   224→          Continue
   225→        </button>
   226→      )}
   227→
   228→      {error && <p className="text-red-500 text-sm text-center">{error}</p>}
   229→    </div>
   230→  );
   231→}
   232→
   233→/* ---------- Questionnaire View ---------- */
   234→
   235→const STYLE_OPTIONS = [
   236→  "Casual", "Streetwear", "Minimalist", "Preppy",
   237→  "Athleisure", "Vintage", "Smart Casual", "Bohemian",
   238→];
   239→
   240→const OCCASION_OPTIONS = [
   241→  "Everyday", "Work", "Date Night", "Workout", "Weekend", "Travel",
   242→];
   243→
   244→function QuestionnaireView({
   245→  onSubmit,
   246→}: {
   247→  onSubmit: (data: OnboardingData) => void;
   248→}) {
   249→  const [brands, setBrands] = useState("");
   250→  const [styles, setStyles] = useState<string[]>([]);
   251→  const [occasions, setOccasions] = useState<string[]>([]);
   252→  const [gender, setGender] = useState("unspecified");
   253→  const [priceMin, setPriceMin] = useState(0);
   254→  const [priceMax, setPriceMax] = useState(300);
   255→
   256→  function toggle(arr: string[], val: string, setter: (v: string[]) => void) {
   257→    setter(arr.includes(val) ? arr.filter((x) => x !== val) : [...arr, val]);
   258→  }
   259→
   260→  function handleSubmit() {
   261→    onSubmit({
   262→      favorite_brands: brands.split(",").map((b) => b.trim()).filter(Boolean),
   263→      style_preferences: styles,
   264→      price_range: { min: priceMin, max: priceMax },
   265→      size_info: {},
   266→      gender,
   267→      occasions,
   268→    });
   269→  }
   270→
   271→  return (
   272→    <div className="p-6 max-w-lg mx-auto pb-20">
   273→      <h2 className="text-2xl font-bold mb-1">Let&apos;s get to know you</h2>
   274→      <p className="text-zinc-500 text-sm mb-6">
   275→        Quick style questions to personalize your experience.
   276→      </p>
   277→
   278→      {/* Gender */}
   279→      <label className="block text-sm font-semibold mb-1.5">Gender</label>
   280→      <select
   281→        value={gender}
   282→        onChange={(e) => setGender(e.target.value)}
   283→        className="w-full px-4 py-3 border border-zinc-200 rounded-xl text-base mb-5 focus:outline-none focus:ring-2 focus:ring-zinc-900"
   284→      >
   285→        <option value="mens">Men</option>
   286→        <option value="womens">Women</option>
   287→        <option value="unspecified">Prefer not to say</option>
   288→      </select>
   289→
   290→      {/* Brands */}
   291→      <label className="block text-sm font-semibold mb-1.5">
   292→        Favorite brands (comma-separated)
   293→      </label>
   294→      <input
   295→        value={brands}
   296→        onChange={(e) => setBrands(e.target.value)}
   297→        placeholder="Nike, Zara, Uniqlo"
   298→        className="w-full px-4 py-3 border border-zinc-200 rounded-xl text-base mb-5 focus:outline-none focus:ring-2 focus:ring-zinc-900"
   299→      />
   300→
   301→      {/* Style */}
   302→      <label className="block text-sm font-semibold mb-2">Style preferences</label>
   303→      <div className="flex flex-wrap gap-2 mb-5">
   304→        {STYLE_OPTIONS.map((s) => (
   305→          <button
   306→            key={s}
   307→            onClick={() => toggle(styles, s, setStyles)}
   308→            className={`px-4 py-2 rounded-full text-sm border transition-colors ${
   309→              styles.includes(s)
   310→                ? "bg-zinc-900 text-white border-zinc-900"
   311→                : "bg-white text-zinc-700 border-zinc-200 hover:border-zinc-400"
   312→            }`}
   313→          >
   314→            {s}
   315→          </button>
   316→        ))}
   317→      </div>
   318→
   319→      {/* Occasions */}
   320→      <label className="block text-sm font-semibold mb-2">Occasions</label>
