    if (!name.trim()) {
      setError("Please enter your name.");
      return;
    }
    onComplete(oauthUser, selfie, name.trim());
  }, [oauthUser, selfie, name, onComplete, setError]);

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 gap-4">
