      {!oauthUser ? (
        <GoogleSignIn
          onSuccess={handleGoogleSuccess}
          onError={setError}
        />
      ) : (
        <div className="flex items-center gap-2 text-sm text-green-600">
          <span>✓</span>
          <span>Signed in as {oauthUser.email}</span>
