   508→    };
   509→
   510→    socket.on("session_ended", handleSessionEnded);
   511→    return () => {
   512→      socket.off("session_ended", handleSessionEnded);
   513→    };
   514→    // eslint-disable-next-line react-hooks/exhaustive-deps
   515→  }, []);
   516→
   517→  // ── Force end from admin ──
   518→  useEffect(() => {
   519→    const handleForceEnd = (data: { user_id?: string }) => {
   520→      if (userId && data.user_id === userId) {
   521→        socket.emit("end_session", { user_id: userId });
   522→      }
   523→    };
   524→
   525→    socket.on("session_force_end", handleForceEnd);
   526→    return () => {
   527→      socket.off("session_force_end", handleForceEnd);
   528→    };
   529→  }, [userId]);
   530→
   531→  // ── Flush queued transcripts when mira stops speaking ──
   532→  useEffect(() => {
   533→    if (!mira.isSpeaking && pendingTranscriptRef.current && userId) {
   534→      socket.emit("mirror_event", {
   535→        user_id: userId,
   536→        event: { type: "voice", transcript: pendingTranscriptRef.current },
   537→      });
   538→      pendingTranscriptRef.current = null;
   539→    }
   540→  }, [mira.isSpeaking, userId]);
   541→
   542→  // ── Forward final STT transcripts (interrupt Mira if speaking) ──
   543→  useEffect(() => {
   544→    if (!stt.transcript || !userId) return;
   545→
   546→    if (mira.isSpeaking) {
   547→      // INTERRUPT: stop TTS/avatar and tell backend to abort the stream
   548→      mira.stop();
   549→      interruptedRef.current = true;
   550→      sentenceBufferRef.current = "";
   551→      currentEmotionRef.current = "idle";
   552→      emotionDetectedRef.current = false;
   553→      setSpeechText("");
   554→      setSpeechVisible(false);
   555→      socket.emit("interrupt", { user_id: userId });
   556→    }
   557→
   558→    // Always send transcript immediately (whether interrupting or not)
   559→    socket.emit("mirror_event", {
   560→      user_id: userId,
   561→      event: { type: "voice", transcript: stt.transcript },
   562→    });
   563→    pendingTranscriptRef.current = null;
   564→    // eslint-disable-next-line react-hooks/exhaustive-deps
   565→  }, [stt.transcript, userId]);
   566→
   567→  // ── Snapshot handler ──
   568→  useEffect(() => {
   569→    const handleSnapshotRequest = () => {
   570→      const video = videoRef.current;
   571→      if (!video || video.readyState < video.HAVE_CURRENT_DATA) return;
   572→
   573→      const canvas = document.createElement("canvas");
   574→      canvas.width = video.videoWidth;
   575→      canvas.height = video.videoHeight;
   576→      const ctx = canvas.getContext("2d");
   577→      if (!ctx) return;
   578→
   579→      ctx.drawImage(video, 0, 0);
   580→      const dataUrl = canvas.toDataURL("image/jpeg", 0.7);
   581→      const base64 = dataUrl.split(",")[1];
   582→
   583→      socket.emit("mirror_event", {
   584→        user_id: userId,
   585→        event: { type: "snapshot", image_base64: base64 },
   586→      });
   587→    };
   588→
   589→    socket.on("request_snapshot", handleSnapshotRequest);
   590→    return () => {
   591→      socket.off("request_snapshot", handleSnapshotRequest);
   592→    };
   593→  }, [videoRef, userId]);
   594→
   595→  // ── Helper: advance to next outfit or emit end_of_outfits ──
   596→  const advanceOrEnd = useCallback(() => {
   597→    setCanvasOutfitIndex((i) => {
   598→      if (i < canvasOutfits.length - 1) {
   599→        return i + 1;
   600→      }
   601→      // At the last outfit — signal end_of_outfits
   602→      setLastGesture("end_of_outfits");
