     1→/**
     2→ * Streaming TTS client using ElevenLabs REST streaming endpoint.
     3→ *
     4→ * Uses fetch + ReadableStream + MediaSource API for low-latency audio playback.
     5→ * Extracts real-time volume via AudioContext + AnalyserNode for Orb visualization.
     6→ *
     7→ * Supports two modes:
     8→ * - speak(): Cancels any current/queued audio and plays immediately (interruption)
     9→ * - speakQueued(): Enqueues a sentence for sequential playback (sentence streaming)
    10→ */
    11→
    12→interface QueueEntry {
    13→  text: string;
    14→  onStart?: () => void;
    15→  onEnd?: () => void;
    16→}
    17→
    18→export class StreamingTTS {
    19→  private apiUrl: string;
    20→  private generation = 0;
    21→  private speaking = false;
    22→  private audio: HTMLAudioElement | null = null;
    23→  private mediaSource: MediaSource | null = null;
    24→  private audioContext: AudioContext | null = null;
    25→  private analyser: AnalyserNode | null = null;
    26→  private sourceNode: MediaElementAudioSourceNode | null = null;
    27→  private frequencyData: Uint8Array<ArrayBuffer> | null = null;
    28→  private pendingResolve: (() => void) | null = null;
    29→
    30→  // Sentence queue for sequential playback
    31→  private queue: QueueEntry[] = [];
    32→  private queueProcessing = false;
    33→  private queueGeneration = 0;
    34→  private onQueueDrain?: () => void;
    35→
    36→  constructor(apiUrl: string) {
    37→    this.apiUrl = apiUrl;
    38→  }
    39→
    40→  /**
    41→   * Stream TTS audio for the given text.
    42→   * CANCELS any current/queued audio and plays immediately.
    43→   * Use this for interruptions or single-shot speech.
    44→   */
    45→  async speak(
    46→    text: string,
    47→    onStart?: () => void,
    48→    onEnd?: () => void,
    49→  ): Promise<void> {
    50→    // Clear the queue — this is an interruption
    51→    this.queue = [];
    52→    this.queueGeneration++;
    53→    this.onQueueDrain = undefined;
    54→
    55→    const gen = ++this.generation;
    56→
    57→    try {
    58→      this.speaking = true;
    59→
    60→      const resp = await fetch(`${this.apiUrl}/api/tts/stream`, {
    61→        method: "POST",
    62→        headers: { "Content-Type": "application/json" },
    63→        body: JSON.stringify({ text }),
    64→      });
    65→
    66→      if (this.generation !== gen) {
    67→        this.speaking = false;
    68→        return;
    69→      }
    70→
    71→      if (!resp.ok || !resp.body) {
    72→        throw new Error(`TTS stream failed: ${resp.status}`);
    73→      }
    74→
    75→      await this.playStream(resp.body, gen, onStart, onEnd);
    76→    } catch (err) {
    77→      console.error("[StreamingTTS] Error:", err);
    78→      this.speaking = false;
    79→      onEnd?.();
    80→    }
    81→  }
    82→
    83→  /**
    84→   * Enqueue a sentence for sequential playback.
    85→   * Sentences play back-to-back without canceling each other.
    86→   * Call onAllDone() to set a callback when the entire queue drains.
    87→   */
    88→  speakQueued(
    89→    text: string,
    90→    onStart?: () => void,
    91→    onEnd?: () => void,
    92→  ): void {
    93→    if (!text.trim()) return;
    94→    this.queue.push({ text, onStart, onEnd });
    95→    this.speaking = true;
    96→    this.processQueue();
    97→  }
    98→
    99→  /**
   100→   * Set a callback that fires when the queue fully drains (all sentences done).
   101→   */
   102→  onAllDone(callback: () => void): void {
   103→    this.onQueueDrain = callback;
   104→  }
   105→
   106→  private async processQueue(): Promise<void> {
   107→    if (this.queueProcessing) return;
   108→    this.queueProcessing = true;
   109→
   110→    const qGen = this.queueGeneration;
   111→
   112→    while (this.queue.length > 0) {
   113→      if (this.queueGeneration !== qGen) break;
   114→
   115→      const entry = this.queue.shift()!;
   116→      const gen = ++this.generation;
   117→
   118→      try {
   119→        console.log(`[StreamingTTS] Queue: playing sentence (${entry.text.length} chars, ${this.queue.length} remaining)`);
   120→
   121→        const resp = await fetch(`${this.apiUrl}/api/tts/stream`, {
   122→          method: "POST",
   123→          headers: { "Content-Type": "application/json" },
   124→          body: JSON.stringify({ text: entry.text }),
   125→        });
   126→
   127→        if (this.generation !== gen || this.queueGeneration !== qGen) {
   128→          entry.onEnd?.();
   129→          break;
   130→        }
   131→
   132→        if (!resp.ok || !resp.body) {
   133→          throw new Error(`TTS stream failed: ${resp.status}`);
   134→        }
   135→
   136→        await this.playStream(resp.body, gen, entry.onStart, entry.onEnd);
   137→      } catch (err) {
   138→        console.error("[StreamingTTS] Queue entry error:", err);
   139→        entry.onEnd?.();
   140→      }
   141→    }
   142→
   143→    this.queueProcessing = false;
   144→
   145→    // If queue is empty and we weren't interrupted, fire drain callback
   146→    if (this.queue.length === 0 && this.queueGeneration === qGen) {
   147→      this.speaking = false;
   148→      const cb = this.onQueueDrain;
   149→      this.onQueueDrain = undefined;
   150→      cb?.();
   151→    }
   152→  }
   153→
   154→  private async playStream(
   155→    body: ReadableStream<Uint8Array>,
   156→    gen: number,
   157→    onStart?: () => void,
   158→    onEnd?: () => void,
   159→  ): Promise<void> {
   160→    return new Promise<void>((resolve) => {
   161→      this.pendingResolve = resolve;
   162→
   163→      const mediaSource = new MediaSource();
   164→      this.mediaSource = mediaSource;
   165→
   166→      const audio = new Audio();
   167→      this.audio = audio;
   168→      audio.src = URL.createObjectURL(mediaSource);
   169→
   170→      // Connect to AudioContext for volume analysis
   171→      this.connectAnalyser(audio);
   172→
   173→      let settled = false;
   174→      const done = () => {
   175→        if (settled) return;
   176→        settled = true;
   177→        this.pendingResolve = null;
   178→        // Don't set speaking=false here — the queue processor manages that
   179→        if (audio.src) {
   180→          URL.revokeObjectURL(audio.src);
   181→        }
   182→        onEnd?.();
   183→        resolve();
   184→      };
   185→
   186→      audio.onerror = done;
   187→      audio.onended = done;
   188→
   189→      mediaSource.addEventListener("sourceopen", () => {
   190→        if (this.generation !== gen) {
   191→          done();
   192→          return;
   193→        }
   194→
   195→        let sourceBuffer: SourceBuffer;
   196→        try {
   197→          sourceBuffer = mediaSource.addSourceBuffer("audio/mpeg");
   198→        } catch {
   199→          console.error("[StreamingTTS] Failed to add source buffer");
   200→          done();
   201→          return;
   202→        }
   203→
   204→        const reader = body.getReader();
   205→        let started = false;
   206→
   207→        const pump = async () => {
   208→          try {
   209→            const { done: readerDone, value } = await reader.read();
   210→
   211→            if (this.generation !== gen) {
   212→              reader.cancel();
   213→              if (mediaSource.readyState === "open") {
   214→                mediaSource.endOfStream();
   215→              }
   216→              done();
   217→              return;
   218→            }
   219→
   220→            if (readerDone) {
   221→              if (mediaSource.readyState === "open" && !sourceBuffer.updating) {
   222→                mediaSource.endOfStream();
   223→              } else if (mediaSource.readyState === "open") {
   224→                sourceBuffer.addEventListener(
   225→                  "updateend",
   226→                  () => {
   227→                    if (mediaSource.readyState === "open") {
   228→                      mediaSource.endOfStream();
   229→                    }
   230→                  },
   231→                  { once: true },
   232→                );
   233→              }
   234→              console.log("[StreamingTTS] Stream complete");
   235→              return;
   236→            }
   237→
   238→            if (sourceBuffer.updating) {
   239→              // Wait for the current update to finish before appending
   240→              await new Promise<void>((res) => {
   241→                sourceBuffer.addEventListener("updateend", () => res(), {
   242→                  once: true,
   243→                });
   244→              });
   245→            }
   246→
   247→            sourceBuffer.appendBuffer(value as unknown as BufferSource);
   248→
   249→            if (!started) {
   250→              started = true;
   251→              console.log("[StreamingTTS] Playback starting");
   252→              onStart?.();
   253→              audio.play().catch(() => {
   254→                console.warn("[StreamingTTS] Autoplay blocked");
   255→              });
   256→            }
   257→
   258→            sourceBuffer.addEventListener("updateend", () => pump(), {
   259→              once: true,
   260→            });
   261→          } catch (err) {
   262→            console.error("[StreamingTTS] Pump error:", err);
   263→            done();
   264→          }
   265→        };
   266→
   267→        pump();
   268→      });
   269→    });
   270→  }
   271→
   272→  private connectAnalyser(audio: HTMLAudioElement): void {
   273→    try {
   274→      if (!this.audioContext) {
   275→        this.audioContext = new AudioContext();
   276→        this.analyser = this.audioContext.createAnalyser();
   277→        this.analyser.fftSize = 256;
   278→        this.analyser.smoothingTimeConstant = 0.7;
   279→        this.analyser.connect(this.audioContext.destination);
   280→        this.frequencyData = new Uint8Array(this.analyser.frequencyBinCount);
   281→      }
   282→
   283→      // Resume context if suspended (browser autoplay policy)
   284→      if (this.audioContext.state === "suspended") {
   285→        this.audioContext.resume();
   286→      }
   287→
   288→      // createMediaElementSource can only be called once per element,
   289→      // so we disconnect the old source and create a new one
   290→      if (this.sourceNode) {
   291→        this.sourceNode.disconnect();
   292→        this.sourceNode = null;
   293→      }
   294→
   295→      const source = this.audioContext.createMediaElementSource(audio);
   296→      source.connect(this.analyser!);
   297→      this.sourceNode = source;
   298→    } catch (err) {
   299→      console.warn("[StreamingTTS] AudioContext setup failed:", err);
   300→    }
   301→  }
   302→
   303→  /**
   304→   * Get current output volume (0-1) for feeding to the Orb component.
   305→   * Uses the same power-curve normalization as ElevenLabs SDK.
   306→   */
   307→  getOutputVolume(): number {
   308→    if (!this.analyser || !this.frequencyData || !this.speaking) return 0;
   309→
   310→    this.analyser.getByteFrequencyData(this.frequencyData);
   311→
   312→    let sum = 0;
   313→    for (let i = 0; i < this.frequencyData.length; i++) {
   314→      sum += this.frequencyData[i];
   315→    }
   316→    const raw = sum / (this.frequencyData.length * 255);
   317→
   318→    // Power-curve normalization (same as ElevenLabs SDK voice-chat blocks)
   319→    return Math.min(1.0, Math.pow(raw, 0.5) * 2.5);
   320→  }
   321→
   322→  /** Stop current playback, clear queue, and cancel any in-flight stream. */
   323→  stop(): void {
   324→    this.generation++;
   325→    this.queueGeneration++;
   326→    this.queue = [];
   327→    this.onQueueDrain = undefined;
   328→    this.speaking = false;
   329→
   330→    if (this.audio) {
   331→      this.audio.pause();
   332→      if (this.audio.src) {
   333→        URL.revokeObjectURL(this.audio.src);
   334→      }
   335→      this.audio = null;
   336→    }
   337→
   338→    if (this.mediaSource?.readyState === "open") {
   339→      try {
   340→        this.mediaSource.endOfStream();
   341→      } catch {
   342→        // Already ended
   343→      }
   344→    }
   345→    this.mediaSource = null;
   346→
   347→    if (this.pendingResolve) {
   348→      this.pendingResolve();
   349→      this.pendingResolve = null;
   350→    }
   351→  }
   352→
   353→  isSpeaking(): boolean {
   354→    return this.speaking;
   355→  }
   356→
   357→  /** Clean up AudioContext on teardown. */
   358→  destroy(): void {
   359→    this.stop();
   360→    if (this.sourceNode) {
   361→      this.sourceNode.disconnect();
   362→      this.sourceNode = null;
   363→    }
   364→    if (this.audioContext) {
   365→      this.audioContext.close();
   366→      this.audioContext = null;
   367→    }
   368→    this.analyser = null;
   369→    this.frequencyData = null;
   370→  }
   371→}
