    34→  });
    35→  return `wss://api.deepgram.com/v1/listen?${params}`;
    36→}
    37→
    38→export interface UseDeepgramSTTReturn {
    39→  isListening: boolean;
    40→  transcript: string;
    41→  interimTranscript: string;
    42→  startListening: () => void;
    43→  stopListening: () => void;
    44→}
    45→
    46→export function useDeepgramSTT(config?: DeepgramSTTConfig): UseDeepgramSTTReturn {
    47→  const [isListening, setIsListening] = useState(false);
    48→  const [transcript, setTranscript] = useState("");
    49→  const [interimTranscript, setInterimTranscript] = useState("");
    50→  const wsRef = useRef<WebSocket | null>(null);
    51→  const streamRef = useRef<MediaStream | null>(null);
    52→  const audioCtxRef = useRef<AudioContext | null>(null);
    53→  const processorRef = useRef<ScriptProcessorNode | null>(null);
    54→  const resumeIntervalRef = useRef<ReturnType<typeof setInterval> | null>(null);
    55→  const reconnectCountRef = useRef(0);
    56→  // Track whether a close was intentional (config change) vs unexpected
    57→  const intentionalCloseRef = useRef(false);
    58→
    59→  const activeConfig = config ?? DEFAULT_CONFIG;
    60→  // Store config in a ref so connectWebSocket always sees the latest values
    61→  const configRef = useRef(activeConfig);
    62→  configRef.current = activeConfig;
    63→
    64→  const cleanup = useCallback(() => {
    65→    if (resumeIntervalRef.current) {
    66→      clearInterval(resumeIntervalRef.current);
    67→      resumeIntervalRef.current = null;
    68→    }
    69→    processorRef.current?.disconnect();
    70→    processorRef.current = null;
    71→    audioCtxRef.current?.close().catch(() => {});
    72→    audioCtxRef.current = null;
    73→    streamRef.current?.getTracks().forEach((t) => t.stop());
    74→    streamRef.current = null;
    75→    if (wsRef.current && wsRef.current.readyState <= WebSocket.OPEN) {
    76→      wsRef.current.close();
    77→    }
    78→    wsRef.current = null;
    79→    reconnectCountRef.current = 0;
    80→    setIsListening(false);
    81→    setInterimTranscript("");
    82→  }, []);
    83→
    84→  const connectWebSocket = useCallback(
    85→    (stream: MediaStream) => {
    86→      if (!DEEPGRAM_API_KEY) {
    87→        console.warn("[DeepgramSTT] No API key configured");
    88→        return;
    89→      }
    90→
    91→      const url = buildDeepgramUrl(configRef.current);
    92→      console.log("[DeepgramSTT] Connecting with URL:", url);
    93→      const ws = new WebSocket(url, ["token", DEEPGRAM_API_KEY]);
    94→      wsRef.current = ws;
    95→
    96→      ws.onopen = () => {
    97→        console.log("[MirrorV2:STT] Connected to Deepgram");
    98→        setIsListening(true);
    99→        reconnectCountRef.current = 0;
   100→
   101→        // Clean up old audio pipeline if reconnecting
   102→        if (resumeIntervalRef.current) {
   103→          clearInterval(resumeIntervalRef.current);
   104→          resumeIntervalRef.current = null;
   105→        }
   106→        processorRef.current?.disconnect();
   107→        audioCtxRef.current?.close().catch(() => {});
   108→
   109→        // Create fresh audio pipeline: mic → AudioContext → ScriptProcessor → WebSocket
   110→        const audioCtx = new AudioContext({ sampleRate: 16000 });
   111→        audioCtxRef.current = audioCtx;
   112→        const source = audioCtx.createMediaStreamSource(stream);
   113→        const processor = audioCtx.createScriptProcessor(4096, 1, 1);
   114→        processorRef.current = processor;
   115→
   116→        processor.onaudioprocess = (e) => {
   117→          if (ws.readyState !== WebSocket.OPEN) return;
   118→          const float32 = e.inputBuffer.getChannelData(0);
   119→          // Convert Float32 PCM to Int16 PCM
   120→          const int16 = new Int16Array(float32.length);
   121→          for (let i = 0; i < float32.length; i++) {
   122→            const s = Math.max(-1, Math.min(1, float32[i]));
   123→            int16[i] = s < 0 ? s * 0x8000 : s * 0x7fff;
   124→          }
   125→          ws.send(int16.buffer);
   126→        };
   127→
   128→        source.connect(processor);
   129→        processor.connect(audioCtx.destination);
   130→
   131→        // Periodically resume AudioContext if browser suspends it (tab switch / idle)
   132→        resumeIntervalRef.current = setInterval(() => {
   133→          if (audioCtx.state === "suspended") {
   134→            audioCtx.resume().catch(() => {});
   135→          }
   136→        }, 3000);
   137→      };
   138→
   139→      ws.onmessage = (event) => {
   140→        try {
   141→          const data = JSON.parse(event.data);
   142→
   143→          // Handle utterance end — clear interim
   144→          if (data.type === "UtteranceEnd") {
   145→            setInterimTranscript("");
   146→            return;
   147→          }
   148→
   149→          const alt = data.channel?.alternatives?.[0];
   150→          if (!alt) return;
   151→
   152→          const text = alt.transcript;
   153→          if (!text) return;
   154→
   155→          // Apply confidence threshold filter
   156→          const confidence = alt.confidence ?? 1.0;
   157→          if (confidence < configRef.current.confidence_threshold) {
   158→            console.log(`[STT] Rejected low-confidence transcript: ${confidence.toFixed(2)} < ${configRef.current.confidence_threshold}`);
   159→            return;
   160→          }
   161→
   162→          if (data.is_final) {
   163→            console.log("[STT] Final transcript:", text, `(confidence: ${confidence.toFixed(2)})`);
   164→            setTranscript(text);
   165→            setInterimTranscript("");
   166→          } else {
   167→            setInterimTranscript(text);
   168→          }
   169→        } catch {
   170→          console.warn("[MirrorV2:STT] Non-JSON message received");
   171→        }
   172→      };
   173→
   174→      ws.onclose = (event) => {
   175→        console.warn("[MirrorV2:STT] Disconnected:", event.reason || `code=${event.code}`);
   176→
   177→        // If this was an intentional close (config change), don't auto-reconnect
   178→        if (intentionalCloseRef.current) {
   179→          intentionalCloseRef.current = false;
   180→          return;
   181→        }
   182→
   183→        // Exponential backoff reconnect (max 3 attempts)
   184→        if (reconnectCountRef.current < MAX_RECONNECTS && streamRef.current) {
   185→          reconnectCountRef.current += 1;
   186→          const delay = Math.min(1000 * Math.pow(2, reconnectCountRef.current - 1), 5000);
   187→          console.warn(`[MirrorV2:STT] Reconnecting, attempt: ${reconnectCountRef.current}/${MAX_RECONNECTS} in ${delay}ms`);
   188→          setTimeout(() => {
   189→            if (streamRef.current) {
   190→              connectWebSocket(streamRef.current);
   191→            }
   192→          }, delay);
   193→        } else if (reconnectCountRef.current >= MAX_RECONNECTS) {
   194→          console.error("[MirrorV2:STT] Max reconnects reached, STT offline");
   195→          setIsListening(false);
   196→        } else {
   197→          setIsListening(false);
   198→        }
   199→      };
   200→
   201→      ws.onerror = () => {
   202→        ws.close();
   203→      };
   204→    },
   205→    [cleanup],
   206→  );
   207→
   208→  // Reconnect WebSocket when config changes (while already listening)
   209→  useEffect(() => {
   210→    if (!wsRef.current || !streamRef.current) return;
   211→
   212→    console.log("[DeepgramSTT] Config changed, reconnecting...");
   213→    intentionalCloseRef.current = true;
   214→    reconnectCountRef.current = 0;
   215→
   216→    // Close existing WebSocket — intentionalCloseRef prevents auto-reconnect in onclose
   217→    if (wsRef.current.readyState <= WebSocket.OPEN) {
   218→      wsRef.current.close();
   219→    }
   220→    wsRef.current = null;
   221→
   222→    // Reconnect with existing mic stream (no re-prompt)
   223→    connectWebSocket(streamRef.current);
   224→    // eslint-disable-next-line react-hooks/exhaustive-deps
   225→  }, [activeConfig.utterance_end_ms, activeConfig.endpointing, activeConfig.confidence_threshold, activeConfig.model, activeConfig.smart_format]);
   226→
   227→  const startListening = useCallback(async () => {
   228→    if (wsRef.current) return;
   229→    reconnectCountRef.current = 0;
   230→
   231→    try {
   232→      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
   233→      streamRef.current = stream;
   234→      connectWebSocket(stream);
   235→    } catch (err) {
   236→      console.error("[MirrorV2:STT] Microphone access failed:", err instanceof Error ? err.message : err);
   237→    }
   238→  }, [connectWebSocket]);
   239→
   240→  const stopListening = useCallback(() => {
   241→    cleanup();
   242→  }, [cleanup]);
   243→
   244→  return { isListening, transcript, interimTranscript, startListening, stopListening };
   245→}
