    29→/**
    30→ * Get the video path for a given emotion and state.
    31→ * - When speaking: use the talking version with lip movement
    32→ * - When idle: use the emotion loop (no lip movement)
    33→ */
    34→function getVideoPath(emotion: MiraEmotion, state: MiraAvatarState): string {
    35→  const basePath = "/avatar/loops/seamless";
    36→  
    37→  if (state === "speaking") {
    38→    // Use talking version with lip movement
    39→    return `${basePath}/talking/${emotion}_talking.mp4`;
    40→  } else {
    41→    // Use emotion loop (no lip movement)
    42→    return `${basePath}/${emotion}_loop.mp4`;
    43→  }
    44→}
    45→
    46→export function MiraVideoAvatar({
    47→  emotion = "idle",
    48→  state = "idle",
    49→  className,
    50→  size = 200,
    51→}: MiraVideoAvatarProps) {
    52→  const videoRef = useRef<HTMLVideoElement>(null);
    53→  const [currentSrc, setCurrentSrc] = useState<string>(() => getVideoPath(emotion, state));
    54→  const [isTransitioning, setIsTransitioning] = useState(false);
    55→
