    77→      videoRef.current.play().catch((err) => {
    78→        console.warn("[MiraVideoAvatar] Autoplay blocked:", err);
    79→      });
    80→    }
    81→  }, [currentSrc]);
    82→
    83→  return (
    84→    <div
    85→      className={className}
    86→      style={{
    87→        width: size,
    88→        height: size,
    89→        overflow: "hidden",
    90→        background: "#000",
    91→        position: "relative",
    92→      }}
    93→    >
    94→      <video
    95→        ref={videoRef}
    96→        src={currentSrc}
    97→        autoPlay
